import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
} from 'reactstrap';
import states from "../api/states";
import PageSpinner from 'components/PageSpinner';
import { findSetup, setSetup} from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";

class FormPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          school : '',
          address : '',
          city:'',
          county:'nn',
          zip:'',
          email:'',
          phone:'',
          website:'',
          motto:'',
          logo_link:'',
          logo:'',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findSetup(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    school: response.data.school,
                    address: response.data.address,
                    city: response.data.city,
                    county: response.data.county,
                    zip: response.data.zip,
                    email: response.data.email,
                    phone: response.data.phone,
                    website: response.data.website,
                    motto: response.data.motto,
                    logo_link:response.data.logo,
                });
                // console.log('response', response);
            }).catch((respError) => {
                console.log('response error', respError);
            });
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    isValidEmailAddress = (email) => {
        if (/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,4}$/i.test(email)) {
            return true;
        }
        return false;
    }

    handleSchoolNameInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, school: v,});
        // console.log(v);
    }
    handleAddressInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, address: v,});
    }
    handleCityInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, city: v,});
    }
    handleCountyInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, county: v,});
    }
    handleZipInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, zip: v,});
    }
    handleEmailInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, email: v,});
    }
    handlePhoneInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, phone: v,});
    }
    handleWebsiteInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, website: v,});
    }
    handleMottoInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, motto: v,});
    }
    handleLogoInput = (event) => {
      const v = event.target.files[0];
      this.setState({...this.state, logo: v,});
    }
    handleSaveChanges = () => {
        this.setState({
          ...this.state,
          preload:true,
        });
        const postData = new FormData();
        postData.append('school', this.state.school);
        postData.append('address', this.state.address);
        postData.append('city', this.state.city);
        postData.append('county', this.state.county);
        postData.append('zip', this.state.zip);
        postData.append('email', this.state.email);
        postData.append('phone', this.state.phone);
        postData.append('website', this.state.website);
        postData.append('motto', this.state.motto);
        if( !(this.state.logo instanceof Blob) )
        {
            this.setState({ 
              ...this.state,
              error: 'upload a valid logo file of type image',
              preload:false,
              msg: '',
            });
            return;
        }
        postData.append('logo', this.state.logo, this.state.logo.name);
        setSetup(this.state.xtoken, postData)
        .then((response) => {
            if( response.status === 200)
            {
                let newstate = {
                    user : response.udata,
                    is_logged_in : true,
                };
                AsyncStorage.setItem(conf.secret, JSON.stringify(newstate)).then((re) => {})
                .catch((errrr) => {});
                this.setState({
                    ...this.state,
                    msg: response.message + '. Changes will take effect on next login',
                    error: '',
                    preload:false,
                });

                this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    preload:false,
                    msg: '',
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
      return (
        <Page title="School Setup" breadcrumbs={[{ name: 'Setup', active: true }]}>
          <Row>
            <Col xl={6} lg={12} md={12}>
              <Card>
                <CardHeader>School information {this.state.preload && (<PageSpinner/>)}</CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleEmail">School name*</Label>
                      <Input onChange={this.handleSchoolNameInput}
                        type="text" 
                        value={this.state.school}
                        name="school"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="examplePassword">Address*</Label>
                      <Input onChange={this.handleAddressInput}
                        type="text"
                        value={this.state.address}
                        name="address"
                        placeholder="e.g. 314 Kimilili lane, off Kitale Rd"
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleUrl">City*</Label>
                      <Input onChange={this.handleCityInput}
                        type="text" 
                        value={this.state.city}
                        name="city"
                        id="city"
                        placeholder="e.g. Plano"
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleSelect">County*</Label>
                      <Input onChange={this.handleCountyInput} value={this.state.county} defaultValue={this.state.county} type="select" name="state">
                        <option value="nn" disabled={true}>Select county</option>
                        {
                            states.data.map((stt, idx) => (
                                <option key={idx} value={stt.name}>{stt.name}</option>
                            ))
                        }
                      </Input>
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleNumber">Zip Code*</Label>
                      <Input onChange={this.handleZipInput}
                        type="number"
                        value={this.state.zip}
                        name="zip"
                        id="zip"
                        placeholder="zip code"
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
    
            <Col xl={6} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="examplePassword">School email*</Label>
                      <Input onChange={this.handleEmailInput}
                        type="email"
                        value={this.state.email}
                        name="email"
                        placeholder="a.valid@email.com"
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="examplePassword">School phone*</Label>
                      <Input onChange={this.handlePhoneInput}
                        type="number"
                        value={this.state.phone}
                        name="phone"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="examplePassword">School Website</Label>
                      <Input onChange={this.handleWebsiteInput}
                        type="url"
                        value={this.state.website}
                        name="web"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="examplePassword">School Motto</Label>
                      <Input onChange={this.handleMottoInput}
                        type="text"
                        value={this.state.motto}
                        name="motto"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="examplePassword">School Logo
                          {this.state.logo_link.length > 1 && (
                              <img
                              src={this.state.logo_link}
                              className="rounded"
                              style={{ width: 50, height: 50, cursor: 'pointer' }}
                              alt={process.env.PUBLIC_URL}
                            />
                          )}
                      </Label>
                      <Input onChange={this.handleLogoInput}
                        type="file"
                        name="motto"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Save changes</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default FormPage;
